    voteFeedback: async function (feedbackId, voteType) {
        try {
            await api.ensureCSRFToken();
            const result = await api.post('/feedback/vote/' + feedbackId, { vote_type: voteType });
            // Update trending suggestions in state
            const trending = store.state.trendingSuggestions || [];
            const idx = trending.findIndex((s) => s.id === feedbackId);
            if (idx >= 0) {
                trending[idx].votes_up = result.votes_up;
                trending[idx].votes_down = result.votes_down;
                trending[idx].user_vote = result.voted ? result.vote_type : null;
                store.setState({ trendingSuggestions: [...trending] });
            }
            toast.success(result.voted ? 'Vote recorded!' : 'Vote removed');
            // Re-render current page
            const currentRoute = store.state.currentPage;
            if (currentRoute === 'feedback-suggestions') {
                renderApp(window.pages.feedbackSuggestions());
            } else if (currentRoute === 'feedback-analytics') {
                renderApp(window.pages.feedbackAnalytics());
            }
        } catch (error) {
            console.error('Error voting:', error);
            toast.error('Failed to vote. Please try again.');
        }
    },

