    // View post details,

    viewPost: async function (postId) {
        try {
            const result = await api.get(`/community/posts/${postId}`);
            modals.viewPost(result);
        } catch (error) {
            const posts = store.state.communityPosts || [];
            const post = posts.find((p) => p.id === postId);
            if (!post) {
                toast.error('Post not found');
                return;
            }
            const author = post.author_name || post.author || store.state.user?.display_name || 'Unknown';
            modals.show(`
                <div class="modal-header">
                    <h2 class="modal-title">${escapeHtml(post.title)}</h2>
                    <button class="modal-close" type="button" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
                </div>
                <div class="modal-body">
                    <p class="text-sm text-gray-500 mb-4">by ${escapeHtml(author)} · ${escapeHtml(post.post_type || post.type || 'Discussion')}</p>
                    <p>${escapeHtml(post.content || post.body || '')}</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" type="button" onclick="modals.close()">Close</button>
                </div>
            `);
        }
    },

    // Submit new post,

    submitCreatePost: async function (event) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        const title = (formData.get('title') || '').trim();
        const content = (formData.get('content') || '').trim();
        if (!title) {
            document.getElementById('post-title')?.focus();
            toast.error('Title is required');
            return;
        }
        if (!content) {
            document.getElementById('post-content')?.focus();
            toast.error('Content is required');
            return;
        }

        const postData = {
            type: formData.get('type'),
            title: title,
            content: content,
            tags: formData.get('tags')
                ? formData
                      .get('tags')
                      .split(',')
                      .map((t) => t.trim())
                      .filter(Boolean)
                : [],
        };

        // Add sale details for success stories
        if (postData.type === 'success') {
            const salePrice = parseFloat(formData.get('salePrice'));
            const profit = parseFloat(formData.get('profit'));

            if (!isNaN(salePrice) && !isNaN(profit)) {
                postData.sale_details = {
                    sale_price: salePrice,
                    profit: profit,
                    platform: formData.get('platform') || '',
                };
            }
        }

        try {
            await api.post('/community/posts', postData);
            toast.success('Post created successfully!');
            modals.close();
            await handlers.loadCommunity();
            renderApp(window.pages.community());
        } catch (error) {
            toast.error('Failed to create post: ' + error.message);
        }
    },

    // React to post,

    reactToPost: async function (postId, reactionType) {
        try {
            await api.post(`/community/posts/${postId}/react`, { reaction_type: reactionType });
            // Reload post details
            await handlers.viewPost(postId);
        } catch (error) {
            toast.error('Failed to react: ' + error.message);
        }
    },

    // Add reply to post,

    submitReply: async function (event, postId) {
        event.preventDefault();
        const form = event.target;
        const content = form.content.value;

        if (!content.trim()) {
            toast.warning('Please enter a reply');
            return;
        }

        try {
            await api.post(`/community/posts/${postId}/replies`, { content });
            toast.success('Reply added!');
            form.reset();
            // Reload post
            await handlers.viewPost(postId);
        } catch (error) {
            toast.error('Failed to add reply: ' + error.message);
        }
    },

    // Delete post,

    deletePost: async function (postId) {
        if (
            !(await modals.confirm('Delete this post? This cannot be undone.', {
                title: 'Delete Post',
                confirmText: 'Delete',
                danger: true,
            }))
        )
            return;

        try {
            await api.delete(`/community/posts/${postId}`);
            toast.success('Post deleted');
            modals.close();
            await handlers.loadCommunity();
        } catch (error) {
            toast.error('Failed to delete post: ' + error.message);
        }
    },

    // Flag post,

    flagPost: async function (postId) {
        const reason = await modals.prompt('Why are you reporting this post?', {
            title: 'Report Post',
            selectOptions: [
                { value: 'Spam', label: 'Spam' },
                { value: 'Inappropriate', label: 'Inappropriate' },
                { value: 'Misleading', label: 'Misleading' },
                { value: 'Harassment', label: 'Harassment' },
                { value: 'Other', label: 'Other' },
            ],
        });
        if (!reason) return;

        try {
            await api.post(`/community/posts/${postId}/flag`, { reason });
            toast.success('Post reported. Thank you!');
        } catch (error) {
            toast.error('Failed to report post: ' + error.message);
        }
    },

